UPDATE AUCTION
SET AUC_STATUS_CD = #{nextStatusCode},
    AUC_UPDT_ID = #{actor},
    AUC_UPDT_DT = NOW()
WHERE AUC_SN = #{auctionId}
  AND AUC_STATUS_CD = #{expectedStatusCode}

UPDATE BID
SET BID_STATUS_CD = #{nextStatusCode},
    BID_UPDT_ID = #{actor},
    BID_UPDT_DT = NOW()
WHERE BID_SN = #{bidId}
  AND BID_STATUS_CD = #{expectedStatusCode}
